# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request
from sklearn.ensemble import RandomForestClassifier
from collections import Counter
import numpy as np
import json

app = Flask(__name__)

# This would be your database in a real application
image_labels = {}

@app.route('/label', methods=['POST'])
def label_image():
    data = request.get_json()
    image_id = data['image_id']
    image_label = data['label']

    if image_id not in image_labels:
        image_labels[image_id] = []

    image_labels[image_id].append(image_label)

    return 'Label added successfully', 200

@app.route('/train', methods=['POST'])
def train_model():
    # This would be your image data in a real application
    images = np.random.rand(100, 100, 3)
    labels = []

    for image_id, image_label in image_labels.items():
        most_common_label = Counter(image_label).most_common(1)[0][0]
        labels.append(most_common_label)

    model = RandomForestClassifier()
    model.fit(images, labels)

    return 'Model trained successfully', 200

if __name__ == '__main__':
    app.run(debug=True)